import React, { useState, useEffect } from 'react';
import { User } from './types';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import Nominations from './components/Nominations';
import Ranking from './components/Ranking';
import Reports from './components/Reports';
import News from './components/News';

type View = 'login' | 'dashboard' | 'nominations' | 'ranking' | 'reports' | 'news';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<View>('login');

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setCurrentView('dashboard');
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setCurrentView('login');
  };

  const renderView = () => {
    if (!currentUser && currentView !== 'login') {
      setCurrentView('login');
      return null;
    }

    switch (currentView) {
      case 'login':
        return <Login onLogin={handleLogin} />;
      case 'dashboard':
        return (
          <Dashboard 
            user={currentUser!} 
            onNavigate={(view: any) => setCurrentView(view)} 
            onLogout={handleLogout}
          />
        );
      case 'nominations':
        return <Nominations onBack={() => setCurrentView('dashboard')} />;
      case 'ranking':
        return <Ranking onBack={() => setCurrentView('dashboard')} />;
      case 'reports':
        return <Reports onBack={() => setCurrentView('dashboard')} />;
      case 'news':
        return <News onBack={() => setCurrentView('dashboard')} />;
      default:
        return <Login onLogin={handleLogin} />;
    }
  };

  return (
    <div className="h-full">
      {renderView()}
    </div>
  );
};

export default App;

